// ── Sanitized accessors ───────────────────────────────────────────────────
//
// The scraped PREREQ_GRAPH has two known bugs from the catalog parser:
//   1) Some courses list themselves as a prereq (e.g. "CSE 21" -> [..., "CSE 21"]).
//   2) "OR" prereqs got flattened into a flat array alongside "AND" prereqs, so the
//      list looks like every course is required when really some are alternatives
//      (e.g. CSE 100 lists MATH 154/158/184/188 — those are alternatives, not all four).
//
// We can't fully fix (2) without re-scraping with a better parser. We do fix (1) and
// expose a `getPrereqGroups` helper that groups by subject so the UI can render them
// as candidate alternative families with a clear disclaimer.

const _cleanPrereqsCache = new Map<string, string[]>()

export function getCleanPrereqs(courseId: string): string[] {
  const cached = _cleanPrereqsCache.get(courseId)
  if (cached) return cached
  const raw = PREREQ_GRAPH[courseId] || []
  const seen = new Set<string>()
  const cleaned: string[] = []
  for (const p of raw) {
    if (!p || p === courseId) continue       // drop self-references
    if (seen.has(p)) continue                 // dedupe
    seen.add(p)
    cleaned.push(p)
  }
  _cleanPrereqsCache.set(courseId, cleaned)
  return cleaned
}

export interface PrereqGroup {
  // Subject prefix (e.g. "MATH", "CSE"). Empty for the "Other" group.
  subject: string
  // Courses in this subject family.
  courses: string[]
  // Heuristic: same-subject groups with 3+ courses at a similar level are usually
  // alternatives ("any of"), not all required. Marked here so the UI can label them.
  likelyAlternatives: boolean
}

const _groupsCache = new Map<string, PrereqGroup[]>()

export function getPrereqGroups(courseId: string): PrereqGroup[] {
  const cached = _groupsCache.get(courseId)
  if (cached) return cached
  const prereqs = getCleanPrereqs(courseId)
  const bySubject = new Map<string, string[]>()
  for (const p of prereqs) {
    const subj = p.split(" ")[0] || "Other"
    if (!bySubject.has(subj)) bySubject.set(subj, [])
    bySubject.get(subj)!.push(p)
  }
  const groups: PrereqGroup[] = []
  for (const [subj, courses] of bySubject) {
    // Heuristic: if there are 3+ courses with the same subject prefix, they're
    // usually alternatives. Smaller same-subject sets are more often legitimate ANDs
    // (e.g. CSE 12 + CSE 15L which is a real two-class prereq pair).
    const likelyAlternatives = courses.length >= 3
    groups.push({
      subject: subj,
      courses: courses.sort(_compareCourseCodes),
      likelyAlternatives,
    })
  }
  groups.sort((a, b) => a.subject.localeCompare(b.subject))
  _groupsCache.set(courseId, groups)
  return groups
}

function _compareCourseCodes(a: string, b: string): number {
  const na = parseInt(a.replace(/^\D+\s*/, ""), 10)
  const nb = parseInt(b.replace(/^\D+\s*/, ""), 10)
  if (!Number.isNaN(na) && !Number.isNaN(nb) && na !== nb) return na - nb
  return a.localeCompare(b)
}

export function getUnlocks(courseId: string): string[] {
  const result: string[] = []
  for (const code of Object.keys(PREREQ_GRAPH)) {
    if (code === courseId) continue
    if (getCleanPrereqs(code).includes(courseId)) result.push(code)
  }
  return result
}

// Memoized depth — derived from the sanitized prereq list. Uses a per-call visited
// set to break cycles AND a global memo so we don't recompute for every layer query.
const _depthMemo = new Map<string, number>()
export function getDepth(courseId: string): number {
  const memo = _depthMemo.get(courseId)
  if (memo !== undefined) return memo
  const d = _depthInner(courseId, new Set())
  _depthMemo.set(courseId, d)
  return d
}

function _depthInner(courseId: string, visiting: Set<string>): number {
  if (visiting.has(courseId)) return 0
  const memo = _depthMemo.get(courseId)
  if (memo !== undefined) return memo
  const prereqs = getCleanPrereqs(courseId)
  if (prereqs.length === 0) {
    _depthMemo.set(courseId, 0)
    return 0
  }
  visiting.add(courseId)
  let max = 0
  for (const p of prereqs) {
    const d = _depthInner(p, visiting)
    if (d > max) max = d
  }
  visiting.delete(courseId)
  const result = 1 + max
  _depthMemo.set(courseId, result)
  return result
}

export function canTake(courseId: string, completed: Set<string>): boolean {
  const prereqs = getCleanPrereqs(courseId)
  if (prereqs.length === 0) return true
  // NOTE: because the underlying data flattens AND/OR, this may flag a course as
  // locked when in reality only ONE of the listed prereqs is actually required.
  // The UI surfaces a disclaimer to that effect.
  return prereqs.every(p => completed.has(p))
}

export type CourseStatus = "completed" | "available" | "locked"
export function getCourseStatus(courseId: string, completed: Set<string>): CourseStatus {
  if (completed.has(courseId)) return "completed"
  if (canTake(courseId, completed)) return "available"
  return "locked"
}

export function getAllDownstream(courseId: string): string[] {
  const result = new Set<string>()
  const queue = getUnlocks(courseId)
  while (queue.length) {
    const next = queue.pop()!
    if (result.has(next)) continue
    result.add(next)
    queue.push(...getUnlocks(next))
  }
  return Array.from(result).sort()
}